Some examples
```C

#include <stdio.h>
#include <math.h>
#include <xmmintrin.h>


static inline void sse_rsqrt( float * restrict pOut, float * restrict pIn )
{
   __m128 in = _mm_load_ss( pIn );
   _mm_store_ss( pOut, _mm_rsqrt_ss( in ) );
   // compiles to movss, movaps, rsqrtss, mulss, movss
}

// plus one newton raphson step
static inline void sse_rsqrt_nr( float * restrict pOut, float * restrict pIn )
{
    const float threehalfs = 1.5F;
    float y, x2;

    x2 = *pIn * 0.5F;

    __m128 in = _mm_load_ss( pIn );
    _mm_store_ss( &y, _mm_rsqrt_ss( in ) );

    *pOut  = y * ( threehalfs - ( x2 * y * y ) );

    // compiles to movss, movaps, rsqrtss, mulss, movss
}


// straight from wikipedia
static inline float carmack_rsqrt( float number )
{
    long i;
    float x2, y;
    const float threehalfs = 1.5F;

    x2 = number * 0.5F;
    y  = number;
    i  = * ( long * ) &y;                       // evil floating point bit level hacking
    i  = 0x5f3759df - ( i >> 1 );               // what the fuck? 
    y  = * ( float * ) &i;
    y  = y * ( threehalfs - ( x2 * y * y ) );   // 1st iteration
    //y  = y * ( threehalfs - ( x2 * y * y ) );   // 2nd iteration, this can be removed

    return y;
}

// with extra NS step
static inline float carmack_rsqrt_ns2( float number )
{
    long i;
    float x2, y;
    const float threehalfs = 1.5F;

    x2 = number * 0.5F;
    y  = number;
    i  = * ( long * ) &y;                       // evil floating point bit level hacking
    i  = 0x5f3759df - ( i >> 1 );               // what the fuck? 
    y  = * ( float * ) &i;
    y  = y * ( threehalfs - ( x2 * y * y ) );   // 1st iteration
    y  = y * ( threehalfs - ( x2 * y * y ) );   // 2nd iteration, this can be removed

    return y;
}


int main(int argc, char** argv)
{

    float x = atof(argv[1]);

    float r, rc, rc2, rsse, rssenr;


    r = 1.0/sqrt(x);
    rc  = carmack_rsqrt(x);
    rc2 = carmack_rsqrt(x);

    sse_rsqrt(&rsse, &x);
    sse_rsqrt_nr(&rssenr, &x);

    printf("carmack 1 nr: %g %g %.16g\n", r, rc, (double)rc/(double)r-1.0);
    printf("carmack 2 nr: %g %g %.16g\n", r, rc, (double)rc/(double)r-1.0);
    printf("sse:          %g %g %.16g\n", r, rsse, (double)rsse/(double)r-1.0);
    printf("sse:    1nr   %g %g %.16g\n", r, rssenr, (double)rssenr/(double)r-1.0);


}
```

